#!/usr/bin/env node
const fs = require("fs");
const path = require("path");

const PATCH_NAME = "customer-feature-gates-account-final-fix";
const root = process.cwd();
const backupRoot = path.join(root, ".barndaksa_patch_backups", `${PATCH_NAME}-${new Date().toISOString().replace(/[:.]/g, "-")}`);

const files = [{"path":"lib/platform/permissions.ts","b64":""},{"path":"components/cafe/cafe-layout.tsx","b64":""},{"path":"components/cafe/cafe-page-client.tsx","b64":""},{"path":"components/cafe/themes/cafe-page-client.tsx","b64":""},{"path":"components/cafe/themes/themed-account-panel.tsx","b64":""},{"path":"app/c/[slug]/account/page.tsx","b64":""},{"path":"app/actions/experience-rewards.ts","b64":""},{"path":"app/actions/loyalty-cards.ts","b64":""},{"path":"app/actions/final-product-release.ts","b64":""},{"path":"app/dashboard/experience-reviews/page.tsx","b64":""},{"path":"app/loyalty-card/[cardCode]/page.tsx","b64":""}];

function ensureDir(filePath) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
}

function backupFile(relPath) {
  const src = path.join(root, relPath);
  if (!fs.existsSync(src)) return;
  const backup = path.join(backupRoot, `${relPath}.txt`);
  ensureDir(backup);
  fs.copyFileSync(src, backup);
}

function writeFile(relPath, b64) {
  const target = path.join(root, relPath);
  backupFile(relPath);
  ensureDir(target);
  fs.writeFileSync(target, Buffer.from(b64, "base64"));
  console.log(`✓ ${relPath}`);
}

function patchTsconfigExclude() {
  const tsconfigPath = path.join(root, "tsconfig.json");
  if (!fs.existsSync(tsconfigPath)) return;
  const raw = fs.readFileSync(tsconfigPath, "utf8");
  let json;
  try {
    json = JSON.parse(raw);
  } catch {
    console.warn("⚠ تعذر قراءة tsconfig.json كـ JSON، تم تخطي الاستثناءات");
    return;
  }

  const excludes = new Set(Array.isArray(json.exclude) ? json.exclude : []);
  [
    "BARNDAKSA_*",
    "BARNDAKSA_PATCH_BACKUPS",
    "BARNDAKSA_PATCH_BACKUPS/**/*",
    ".barndaksa_patch_backups",
    ".barndaksa_patch_backups/**/*",
  ].forEach((item) => excludes.add(item));
  json.exclude = Array.from(excludes);

  backupFile("tsconfig.json");
  fs.writeFileSync(tsconfigPath, `${JSON.stringify(json, null, 2)}\n`);
  console.log("✓ tsconfig.json");
}

console.log("Applying BARNDAKSA customer feature gates/account final fix...");
fs.mkdirSync(backupRoot, { recursive: true });
for (const file of files) writeFile(file.path, file.b64);
patchTsconfigExclude();
console.log("\nتم تطبيق الباتش بنجاح.");
console.log(`نسخة احتياطية نصية: ${backupRoot}`);
console.log("شغّل الآن: npm exec tsc -- --noEmit ثم npm run build");
